@import (reference) "../style/themes/default.less";

.am-filter {
  &-show {
    height: 100vh;
    display: block;
    position: relative;
  }

  &-hide {
    display: none;
  }

  &-mask, &-document {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
  }

  &-mask {
    bottom: 0;
    background: @color-product-mask;
    background: var(--am-filter-mask, @color-product-mask);
  }

  &-content {
    background: @color-fill-grey-inverse;
    background: var(--am-filter-content-bgc, @color-fill-grey-inverse);
    display: flex;
    flex-direction: column;
    overflow-x: hidden;
    overflow-y: scroll;
  }

  &-list {
    flex: 1;
    padding-left: @size-3;
    padding-left: var(--am-filter-padding, @size-3);
    padding-bottom: @size-3;
    padding-bottom: var(--am-filter-padding, @size-3);
    overflow-x: hidden;
    overflow-y: scroll;
    max-height: 830 * @pixelSize;
    box-sizing: border-box;
  }

  &-btn {
    width: 100%;
    display: flex;
  }

  &-default, &-primary {
    flex: 1;
    height: @size-12;
    height: var(--am-filter-button-height, @size-12);
    font-size: @font-size-title;
    font-size: var(--am-filter-button-fontSize, @font-size-title);
    box-sizing: border-box;
    width: 50%;
    border: 0;
    border-radius: 0;
  }

  &-default {
    border-top: @border-width-standard solid #eee;
    border-right: none;
  }

  &-child-2 {
    & > .am-filter-item-wrap {
      width: 50%;
    }
  }

  &-child-3 {
    & > .am-filter-item-wrap {
      width: 33.3%;
    }
  }
}

@import (reference) "../style/themes/default.less";
.am-loading {
  &-wrap {
    display: flex;
    justify-content: center;
    align-items: center;
    width: @size-1;
    width: var(--am-loading-item-size, @size-1);
    height: @size-1;
    height: var(--am-loading-item-size, @size-1);
    min-width: 66 * @pixelSize;
    min-height: 66 * @pixelSize;
  }
  &-item {
    flex: 0 0 8 * @pixelSize;
    min-width: 6 * @pixelSize;
    min-height: 6 * @pixelSize;
    max-width: 8 * @pixelSize;
    max-height: 8 * @pixelSize;
    overflow: hidden;
    margin-right: @h-spacing-standard;
    margin-right: var(--am-loading-marginR, @h-spacing-standard);
    border-radius: @corner-radius-sm / 2;
    border-radius: var(--am-loading-item-radius, calc(@corner-radius-sm / 2));
    background-color: @color-text-subtitle;
    background-color: var(--am-color-text-subtitle, @color-text-subtitle);
    animation: aliui_loading_animation 1s 0s infinite linear;
    &__1 {
      animation-delay: 0s;
    }
    &__2 {
      animation-delay: 150ms;
    }
    &__3 {
      margin-right: 0;
      animation-delay: 300ms;
    }
  }
}

@keyframes aliui_loading_animation {
  0% {
    transform: translate3d(0, 0, 0);
  }
  12% {
    transform: translate3d(0, -150%, 0);
  }
  40% {
    transform: translate3d(0, 110%, 0);
  }
  55% {
    transform: translate3d(0, -10%, 0);
  }
  60% {
    transform: translate3d(0, 0, 0);
  }
  100% {
    transform: translate3d(0, 0, 0);
  }
}

@import '../../style/mixins/hairline.less';

.am-popover-item {
  // min-width: 80px;
  max-width: 170px;
  padding: 0 @h-spacing-large;
  padding: 0 var(--am-popover-item-padding, @h-spacing-large);
  &-hover {
    background-color: #f2f2f2;
  }
  &-wrapper {
    position: relative;
    padding-top: @h-spacing-large;
    padding-top: var(--am-popover-item-padding, @h-spacing-large);
    padding-bottom: @h-spacing-large;
    padding-bottom: var(--am-popover-item-padding, @h-spacing-large);
    padding-right: @size-9;
    padding-right: var(--am-popover-item-padding-right, @size-9);
    font-size: @font-size-subtitle;
    font-size: var(--am-popover-item-font-size, @font-size-subtitle);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    color: @color-text-title;
    color: var(--am-popover-item-font-color, @color-text-title);
    display: flex;
    align-items: center;
    // .hairline("bottom", #eee);
  }
  &-icon-holder {
    height: @icon-size-sm;
    height: var(--am-popover-item-icon-size, @icon-size-sm);
    width: @icon-size-sm;
    width: var(--am-popover-item-icon-size, @icon-size-sm);
  }
  &-ver-center {
    display: flex;
    align-items: center;
  }
  &-slot-holder {
    padding-left: @h-spacing-large;
    padding-left: var(--am-popover-item-icon-text-space, @h-spacing-large);
  }
}
.am-popover-item:not(:last-child) > .am-popover-item-wrapper {
  // border-bottom: 1px solid #e5e5e5;
  .hairline('bottom');
}

//
// Jumbotron
// --------------------------------------------------
@jumbotron-padding:              30px;
@jumbotron-color:                inherit;
@jumbotron-bg:                   #666;
@jumbotron-heading-color:        inherit;
@jumbotron-font-size:            14px;
@jumbotron-heading-font-size:    28px;

.jumbotron {
  padding-top: @jumbotron-padding;
  padding-bottom: @jumbotron-padding;
  margin-bottom: @jumbotron-padding;
  color: @jumbotron-color;
  background-color: @jumbotron-bg;

  h1,
  .h1 {
    color: @jumbotron-heading-color;
  }

  p {
    margin-bottom: (@jumbotron-padding / 2);
    font-size: @jumbotron-font-size;
    font-weight: 200;
  }

  > hr {
    border-top-color: darken(@jumbotron-bg, 10%);
  }

  .container &,
  .container-fluid & {
    border-radius: @border-radius-large; // Only round corners at higher resolutions if contained in a container
    padding-left: (@grid-gutter-width / 2);
    padding-right: (@grid-gutter-width / 2);
  }

  .container {
    max-width: 100%;
  }

  @media screen and (min-width: @screen-sm-min) {
    padding-top: (@jumbotron-padding * 1.6);
    padding-bottom: (@jumbotron-padding * 1.6);

    .container &,
    .container-fluid & {
      padding-left: (@jumbotron-padding * 2);
      padding-right: (@jumbotron-padding * 2);
    }

    h1,
    .h1 {
      font-size: @jumbotron-heading-font-size;
    }
  }
}

// Amaze UI for legacy browsers
//
// =============================================================================

// button-group.less
// Justify button group
// =============================================================================

// Justify button group
.hook-button-group-justify() {
  .lte9 & {
    display: table;
    table-layout: fixed;
    border-collapse: separate;

    > .@{ns}btn,
    > .@{ns}btn-group {
      float: none;
      display: table-cell;
      width: 1%;
    }
  }
}

// Justify nav
.hook-nav-justify() {
  .lte9 & {
    & > li {
      display: table-cell;
      width: 1%;
    }
  }
}

// JS Progress
.lte9 {
  // no CSS animation，hide spinner
  #nprogress {
    .nprogress-spinner {
      display: none !important;
    }
  }
}

.lte8 {
  .@{ns}dimmer {
    background-color: #000;
    filter: ~"alpha(opacity=60)";
  }

  .@{ns}modal-actions {
    display: none;

    &.@{ns}modal-active {
      display: block;
    }
  }

  // Plugin OffCanvas rgba() bg
  .@{ns}﻿offcanvas.@{ns}active {
    background: #000;
  }

  // Plugin Popover: caret style
  .@{ns}popover .@{ns}popover-caret {
    border: 8px solid transparent;
  }

  .@{ns}popover-top .@{ns}popover-caret {
    border-top: 8px solid @popover-bg;
    border-bottom: none;
  }

  .@{ns}popover-left .@{ns}popover-caret {
    right: -8px;
    margin-top: -6px;
    border-left: 8px solid @popover-bg;
    border-right: none;
  }

  .@{ns}popover-right .@{ns}popover-caret {
    left: -8px;
    margin-top: -6px;
    border-right: 8px solid @popover-bg;
    border-left: none;
  }
}

@class-prefix-dialog: ~'adm-dialog';

.@{class-prefix-dialog} {
  --z-index: var(--adm-dialog-z-index, 1000);

  ---z-index: var(--z-index);
  .adm-center-popup {
    --z-index: var(---z-index);
  }
}

.@{class-prefix-dialog}-body {
  width: 100%;
  max-height: 70vh;
  font-size: var(--adm-font-size-6);
  overflow: hidden;

  display: flex;
  flex-direction: column;
  > * {
    flex: none;
  }
  > .adm-dialog-content {
    flex: auto;
  }

  &:not(.adm-dialog-with-image) {
    padding-top: 20px;
  }
}

.adm-dialog-image-container {
  margin-bottom: 12px;
  max-height: 40vh;
}
.adm-dialog-header {
  margin-bottom: 8px;
  padding: 0 12px;
}
.adm-dialog-title {
  margin-bottom: 8px;
  padding: 0 12px;
  font-weight: bold;
  font-size: var(--adm-font-size-10);
  line-height: 25px;
  text-align: center;
}
.adm-dialog-content {
  padding: 0 12px 20px;
  max-height: 70vh;
  overflow-x: hidden;
  overflow-y: auto;
  font-size: var(--adm-font-size-7);
  line-height: 1.4;
  color: var(--adm-color-text);
  &-empty {
    padding: 0;
    height: 12px;
  }
}
.@{class-prefix-dialog}-footer {
  user-select: none;
  .adm-dialog-action-row {
    display: flex;
    align-items: stretch;
    border-top: 0.5px solid var(--adm-color-border);
    > * {
      flex: 1;
    }
    > .adm-dialog-button {
      padding: 10px;
      font-size: var(--adm-font-size-10);
      line-height: 25px;
      border-radius: 0;
      &-bold {
        font-weight: bold;
      }
      border-right: solid 0.5px var(--adm-color-border);
      &:last-child {
        border-right: none;
      }
    }
  }
}

.@{class-prefix-dialog}-image-container {
  overflow-y: auto;
}

@class-prefix-modal: ~'adm-modal';

.@{class-prefix-modal} {
  --z-index: var(--adm-modal-z-index, 1000);

  ---z-index: var(--z-index);
  .adm-center-popup {
    --z-index: var(---z-index);
  }
}

.@{class-prefix-modal}-body {
  width: 100%;
  max-height: 70vh;
  font-size: var(--adm-font-size-6);
  overflow: hidden;

  display: flex;
  flex-direction: column;
  > * {
    flex: none;
  }
  > .adm-modal-content {
    flex: auto;
  }

  &:not(.adm-modal-with-image) {
    padding-top: 20px;
  }
}

.adm-modal-image-container {
  margin-bottom: 12px;
  max-height: 40vh;
  overflow-y: scroll;
}
.adm-modal-header {
  margin-bottom: 8px;
  padding: 0 12px;
}
.adm-modal-title {
  margin-bottom: 8px;
  padding: 0 12px;
  font-weight: bold;
  font-size: var(--adm-font-size-10);
  line-height: 25px;
  text-align: center;
}
.adm-modal-content {
  padding: 0 12px 12px;
  max-height: 70vh;
  overflow-x: hidden;
  overflow-y: auto;
  font-size: var(--adm-font-size-7);
  line-height: 1.4;
  color: var(--adm-color-text);
}

.adm-modal-footer {
  user-select: none;
  padding: 8px 12px 12px;
  &-empty {
    padding: 0;
    height: 8px;
  }
  &.adm-space {
    --gap-vertical: 20px;
  }
  .adm-modal-button {
    font-size: var(--adm-font-size-10);
    line-height: 25px;
    &:not(.adm-modal-button-primary) {
      padding-top: 0;
      padding-bottom: 0;
      &::before {
        display: none;
      }
      &:active {
        opacity: 0.7;
      }
    }
  }
}

@class-prefix-popover: ~'adm-popover';

.@{class-prefix-popover} {
  --z-index: var(--adm-popover-z-index, 1030);

  --background: #ffffff;
  --arrow-size: 8px;
  --content-padding: 8px 12px;

  &&-dark {
    --background: rgba(0, 0, 0, 0.75);
    --adm-color-text: #ffffff;
    color: #ffffff;
    .adm-popover-inner {
      box-shadow: none;
    }
  }

  color: var(--adm-color-text);
  position: absolute;
  top: 0;
  left: 0;
  z-index: var(--z-index);
  white-space: normal;
  text-align: left;
  cursor: auto;
  user-select: text;
  animation: none;

  &::after {
    position: absolute;
    background: fade(#ffffff, 1%);
    content: '';
  }
  &-hidden {
    display: none;
  }

  &-inner {
    background-color: var(--background);
    background-clip: padding-box;
    border-radius: 8px;
    box-shadow: 0 0 30px 0 rgba(51, 51, 51, 0.2);
    font-size: var(--adm-font-size-7);
    width: max-content;
    min-width: 32px;
    max-width: calc(100vw - 24px);
    overflow-y: hidden;
    &-content {
      padding: var(--content-padding);
    }
  }

  &-arrow {
    position: absolute;
    display: block;
    height: var(--arrow-size);
    width: var(--arrow-size);
    overflow: visible;
    background: transparent;
  }

  &-arrow-icon {
    display: block;
    height: var(--arrow-size);
    width: calc(var(--arrow-size) / 8 * 15);
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%) rotate(var(--arrow-icon-rotate));
  }

  .adm-popover-arrow {
    color: var(--background);
  }
}

@class-prefix-picker: ~'adm-picker';

.@{class-prefix-picker} {
  --header-button-font-size: var(--adm-font-size-7);
  --title-font-size: var(--adm-font-size-7);
  --item-font-size: var(--adm-font-size-8);
  --item-height: 34px;

  width: 100%;
  height: 300px;
  overflow: hidden;
  position: relative;
  display: flex;
  flex-direction: column;

  ---item-font-size: var(--item-font-size);
  ---item-height: var(--item-height);
  .adm-picker-view.adm-picker-view {
    --item-font-size: var(---item-font-size);
    --item-height: var(---item-height);
  }
}

.@{class-prefix-picker}-header {
  flex-shrink: 0;
  border-bottom: solid 1px var(--adm-color-border);
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 4px;
  &-button {
    font-size: var(--header-button-font-size);
    display: inline-block;
    padding: 8px 8px;
    &-disabled {
      &,
      &:active {
        opacity: 0.4;
        cursor: not-allowed;
      }
    }
  }
  &-title {
    padding: 4px 4px;
    font-size: var(--title-font-size);
    color: var(--adm-color-text);
    text-align: center;
    flex: 1;
  }
}

.@{class-prefix-picker}-body {
  flex: 1;
  width: 100%;
  height: 100%;

  > .adm-picker-view {
    --height: 100%;
  }
}

.@{class-prefix-picker}-popup {
  & .adm-popup-body {
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
  }
}

@class-prefix-error-block: ~'adm-error-block';

.@{class-prefix-error-block} {
  --color: var(--adm-color-text);
  --image-height: var(--adm-error-block-image-height, 100px);
  --image-height-full-page: var(
    --adm-error-block-image-height-full-page,
    200px
  );
  --image-width: var(--adm-error-block-image-width, auto);
  --image-width-full-page: var(--adm-error-block-image-width-full-page, auto);

  box-sizing: border-box;
  text-align: center;

  &-image {
    height: var(--image-height);
    width: var(--image-width);
    max-width: 100%;

    & svg,
    img {
      height: 100%;
    }
  }

  &-description {
    font-size: var(--adm-font-size-4);
    color: var(--adm-color-weak);
    line-height: 1.4;
    margin-top: 12px;
    &-title {
      font-size: var(--adm-font-size-7);
    }
    &-subtitle {
      margin-top: 8px;
    }
  }

  &-content {
    margin-top: 12px;
  }

  &-full-page {
    padding-top: calc(50vh - var(--image-height-full-page));
    .@{class-prefix-error-block}-image {
      height: var(--image-height-full-page);
      width: var(--image-width-full-page);
    }
    .@{class-prefix-error-block}-description {
      margin-top: 20px;
      font-size: var(--adm-font-size-main);
      &-title {
        font-size: 20px;
        color: var(--adm-color-text);
      }
    }
  }
}

