@import '../custom.less';

@skeleton-item-prefix-cls: ~'@{css-prefix}skeleton-item';

.@{skeleton-item-prefix-cls} {
  @apply bg-color-fill-3;
  @apply rounded-sm;

  &--active {
    &.@{skeleton-item-prefix-cls} {
      @apply bg-gradient-to-r;
      @apply from-color-border-separator;
      @apply via-color-bg-2;
      @apply to-color-border-separator;
      @apply bg-w200h100;
      @apply animate-skeleton-loading-1500ms;
    }
  }

  &--square {
    @apply mb-3;
    @apply w-full;
    @apply h-12;
  }

  &--circle {
    @apply rounded-full;
    &.@{skeleton-item-prefix-cls} {
      &--small {
        @apply w-6;
        @apply h-6;
      }

      &--medium {
        @apply w-7;
        @apply h-7;
      }

      &--large {
        @apply w-8;
        @apply h-8;
      }
    }
  }

  &--image {
    @apply flex;
    @apply justify-center;
    @apply items-center;

    svg {
      @apply w-2/5;
      @apply h-2/5;
      @apply fill-color-border;
    }

    &.@{skeleton-item-prefix-cls} {
      &--small {
        @apply w-6;
        @apply h-6;
      }

      &--medium {
        @apply w-7;
        @apply h-7;
      }

      &--large {
        @apply w-8;
        @apply h-8;
      }
    }
  }
}

@import '../custom.less';

@scrollbar-prefix-cls: ~'@{css-prefix}scrollbar';

.@{scrollbar-prefix-cls} {
  @apply overflow-hidden;
  @apply relative;

  &:active > &__bar,
  &:focus > &__bar,
  &:hover > &__bar {
    @apply opacity-100;
    transition: opacity 340ms ease-out;
  }

  &__wrap {
    @apply overflow-scroll;
    @apply h-full;
  }

  &__wrap--hidden-default::-webkit-scrollbar {
    @apply w-0;
    @apply h-0;
  }

  &__thumb {
    @apply relative;
    @apply block;
    @apply w-0;
    @apply h-0;
    @apply cursor-pointer;
    border-radius: inherit;
    @apply bg-color-fill-1;
    transition: 0.3s background-color;

    &:hover {
      @apply bg-color-fill-7;
    }
  }

  &__bar {
    @apply absolute;
    @apply ~'right-0.5';
    @apply ~'bottom-0.5';
    @apply ~'z-[1]';
    @apply rounded-full;
    @apply opacity-0;
    transition: opacity 120ms ease-out;

    &.is-show {
      @apply opacity-100;
    }

    &.is-vertical {
      @apply ~'w-1.5';
      @apply ~'top-0.5';

      & > div {
        @apply w-full;
      }

      &:has(.@{css-prefix}scrollbar__thumb:hover) {
        @apply ~'w-2.5';
      }
    }

    &.is-horizontal {
      @apply ~'h-1.5';
      @apply ~'left-0.5';

      & > div {
        @apply h-full;
      }

      &:has(.@{css-prefix}scrollbar__thumb:hover) {
        @apply ~'h-2.5';
      }
    }
  }
}

//
// Alerts
// --------------------------------------------------


// Base styles
// -------------------------

.alert {
  padding: 8px 35px 8px 14px;
  margin-bottom: @baseLineHeight;
  text-shadow: 0 1px 0 rgba(255,255,255,.5);
  background-color: @warningBackground;
  border: 1px solid @warningBorder;
  .border-radius(@baseBorderRadius);
}
.alert,
.alert h4 {
  // Specified for the h4 to prevent conflicts of changing @headingsColor
  color: @warningText;
}
.alert h4 {
  margin: 0;
}

// Adjust close link position
.alert .close {
  position: relative;
  top: -2px;
  right: -21px;
  line-height: @baseLineHeight;
}


// Alternate styles
// -------------------------

.alert-success {
  background-color: @successBackground;
  border-color: @successBorder;
  color: @successText;
}
.alert-success h4 {
  color: @successText;
}
.alert-danger,
.alert-error {
  background-color: @errorBackground;
  border-color: @errorBorder;
  color: @errorText;
}
.alert-danger h4,
.alert-error h4 {
  color: @errorText;
}
.alert-info {
  background-color: @infoBackground;
  border-color: @infoBorder;
  color: @infoText;
}
.alert-info h4 {
  color: @infoText;
}


// Block alerts
// -------------------------

.alert-block {
  padding-top: 14px;
  padding-bottom: 14px;
}
.alert-block > p,
.alert-block > ul {
  margin-bottom: 0;
}
.alert-block p + p {
  margin-top: 5px;
}

